import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const BusinessDetails = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { squareNumber, duration, pageNumber } = location.state || {};
  
  const [formData, setFormData] = useState({
    businessName: '',
    email: '',
    dealLink: '',
    logo: null
  });
  
  const [logoPreview, setLogoPreview] = useState(null);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert('File size must be less than 2MB');
        return;
      }
      
      setFormData(prev => ({ ...prev, logo: file }));
      
      const reader = new FileReader();
      reader.onload = (e) => {
        setLogoPreview(e.target.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Validate form
    if (!formData.businessName || !formData.email || !formData.dealLink || !formData.logo) {
      alert('Please fill in all required fields');
      return;
    }

    // Navigate to payment page with all data
    navigate('/checkout', {
      state: {
        squareNumber,
        duration,
        pageNumber,
        ...formData,
        logoPreview
      }
    });
  };

  const totalAmount = duration; // £1 per day

  return (
    <div className="checkout-container">
      <div className="checkout-header">
        <h1>🛍️ Business & Advertisement Details</h1>
        <p>Complete your advertising campaign setup</p>
      </div>

      <div className="checkout-content">
        {/* Order Summary */}
        <div className="order-summary">
          <h3>📋 Order Summary</h3>
          <div className="summary-details">
            <div className="summary-item">
              <span>Square Number:</span>
              <strong>#{squareNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Page:</span>
              <strong>Page {pageNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Duration:</span>
              <strong>{duration} days</strong>
            </div>
            <div className="summary-item total">
              <span>Total Amount:</span>
              <strong>£{totalAmount}.00</strong>
            </div>
          </div>
        </div>

        {/* Business Details Form */}
        <form className="business-form" onSubmit={handleSubmit}>
          <div className="form-section">
            <h3>🏢 Business Information</h3>
            
            <div className="form-group">
              <label htmlFor="businessName">Business Name *</label>
              <input
                type="text"
                id="businessName"
                name="businessName"
                value={formData.businessName}
                onChange={handleInputChange}
                placeholder="Enter your business name"
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="email">Email Address *</label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                placeholder="Enter your email address"
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="dealLink">Deals/Discounts Link *</label>
              <input
                type="url"
                id="dealLink"
                name="dealLink"
                value={formData.dealLink}
                onChange={handleInputChange}
                placeholder="https://yourwebsite.com/deals"
                required
              />
              <small>This is where customers will be directed when they click your logo</small>
            </div>
          </div>

          <div className="form-section">
            <h3>🖼️ Company Logo</h3>
            
            <div className="form-group">
              <label htmlFor="logoUpload">Upload Logo *</label>
              <input
                type="file"
                id="logoUpload"
                accept="image/*"
                onChange={handleLogoUpload}
                required
              />
              <small>PNG, JPG up to 2MB. Recommended: Square logo for best display</small>
            </div>

            {logoPreview && (
              <div className="logo-preview">
                <h4>Logo Preview:</h4>
                <img src={logoPreview} alt="Logo preview" />
              </div>
            )}
          </div>

          <div className="form-actions">
            <button type="button" className="btn-secondary" onClick={() => navigate(-1)}>
              ← Back
            </button>
            <button type="submit" className="btn-primary">
              Continue to Payment →
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BusinessDetails;
